 5→
 6→export const PRESETS = {
 7→  // Match the SVG blueprint's top/bottom and left/right reading in the preview.
 8→  plan_aligned: new THREE.Vector3(-1.1, 0.92, 1.05),
 9→  default: new THREE.Vector3(-1.1, 0.92, 1.05),
10→  iso_northeast: new THREE.Vector3(1, 0.88, 1),
11→  iso_northwest: new THREE.Vector3(-1, 0.88, 1),
12→  iso_southeast: new THREE.Vector3(1, 0.88, -1),
13→  iso_southwest: new THREE.Vector3(-1, 0.88, -1),
14→};
