16→export const WALK_EYE_HEIGHT = 1700;
17→export const WALK_MOVE_SPEED = 1800;
18→export const WALK_SPRINT_MULTIPLIER = 1.8;
19→export const WALK_LOOK_DISTANCE = 1200;
20→export const DEFAULT_WALK_DIRECTION = new THREE.Vector3(1, 0, -1).normalize();
